<template>
  <Teleport to="body">
    <Transition name="overlay">
      <div v-if="show" class="modal-overlay" @click="handleOverlayClick">
        <Transition name="modal">
          <div v-if="show" class="modal-container" @click.stop>
            <!-- 弹窗头部 -->
            <div v-if="$slots.header || title" class="modal-header">
              <div class="header-left">
                <slot name="header">
                  <h2 v-if="title" class="modal-title">{{ title }}</h2>
                </slot>
              </div>
              <button v-if="showClose" class="modal-close-btn" @click="handleClose">
                ×
              </button>
            </div>

            <!-- 弹窗内容 -->
            <div class="modal-body">
              <slot>
                <p v-if="content">{{ content }}</p>
              </slot>
            </div>

            <!-- 弹窗底部 -->
            <div v-if="$slots.footer || showButtons" class="modal-footer">
              <slot name="footer">
                <KidButton
                  v-if="showCancel"
                  variant="outline"
                  @click="handleCancel"
                >
                  {{ cancelText }}
                </KidButton>
                <KidButton
                  v-if="showConfirm"
                  :variant="confirmVariant"
                  @click="handleConfirm"
                >
                  {{ confirmText }}
                </KidButton>
              </slot>
            </div>
          </div>
        </Transition>
      </div>
    </Transition>
  </Teleport>
</template>

<script setup lang="ts">
import { ref, watch } from 'vue';
import { useModal } from '@/composables/useModal';
import KidButton from '@/components/ui/KidButton.vue';

interface Props {
  show?: boolean;
  title?: string;
  content?: string;
  showClose?: boolean;
  closeOnClickOverlay?: boolean;
  showButtons?: boolean;
  showCancel?: boolean;
  showConfirm?: boolean;
  cancelText?: string;
  confirmText?: string;
  confirmVariant?: 'primary' | 'success' | 'danger' | 'outline' | 'text';
}

const props = withDefaults(defineProps<Props>(), {
  show: false,
  showClose: true,
  closeOnClickOverlay: true,
  showButtons: false,
  showCancel: true,
  showConfirm: true,
  cancelText: '取消',
  confirmText: '确定',
  confirmVariant: 'primary'
});

const emit = defineEmits<{
  'update:show': [value: boolean];
  close: [];
  cancel: [];
  confirm: [];
}>();

const show = ref(props.show);

// 监听外部 show 变化
watch(() => props.show, (val) => {
  show.value = val;
});

// 使用 useModal composable
const { close } = useModal({
  show,
  onClose: handleClose,
  lockBodyScroll: true,
  closeOnEscape: true
});

function handleClose() {
  show.value = false;
  emit('update:show', false);
  emit('close');
}

function handleCancel() {
  show.value = false;
  emit('update:show', false);
  emit('cancel');
}

function handleConfirm() {
  emit('confirm');
}

function handleOverlayClick() {
  if (props.closeOnClickOverlay) {
    handleClose();
  }
}

// 暴露方法
defineExpose({
  close,
  open: () => {
    show.value = true;
    emit('update:show', true);
  }
});
</script>

<style scoped lang="scss">
@import '@/styles/modal.scss';
</style>
