/**
 * HTTP 请求基类
 * 封装通用的请求逻辑和错误处理
 */
import type { ApiResponse } from './api.types';
import { API_CONSTANTS } from './api.types';

export class BaseApiService {
  protected baseUrl: string;
  protected token: string | null = null;

  constructor() {
    this.baseUrl = import.meta.env.VITE_API_URL || API_CONSTANTS.DEFAULT_API_URL;
    this.loadToken();
  }

  /**
   * 设置基础 URL
   */
  setBaseUrl(url: string): void {
    this.baseUrl = url;
  }

  /**
   * 设置 Token
   */
  setToken(token: string): void {
    this.token = token;
    localStorage.setItem(API_CONSTANTS.TOKEN_KEY, token);
  }

  /**
   * 清除 Token
   */
  clearToken(): void {
    this.token = null;
    localStorage.removeItem(API_CONSTANTS.TOKEN_KEY);
  }

  /**
   * 加载 Token
   */
  protected loadToken(): void {
    this.token = localStorage.getItem(API_CONSTANTS.TOKEN_KEY);
  }

  /**
   * 获取当前 Token
   */
  protected getCurrentToken(): string | null {
    return this.token;
  }

  /**
   * 构建请求头
   */
  protected buildHeaders(headers: HeadersInit = {}): HeadersInit {
    const resultHeaders: HeadersInit = {
      'Content-Type': 'application/json',
      ...headers,
    };

    const currentToken = this.getCurrentToken();
    if (currentToken) {
      resultHeaders['Authorization'] = `Bearer ${currentToken}`;
    }

    return resultHeaders;
  }

  /**
   * 通用请求方法
   */
  protected async request<T>(
    url: string,
    options: RequestInit = {}
  ): Promise<ApiResponse<T>> {
    const headers = this.buildHeaders(options.headers);

    // 如果有 body 且没有显式设置 Content-Type，则默认为 application/json
    if (options.body && !headers['Content-Type']) {
      headers['Content-Type'] = 'application/json';
    }

    try {
      const response = await fetch(`${this.baseUrl}${url}`, {
        ...options,
        headers,
        mode: 'cors',
        credentials: 'include',
      });

      if (!response.ok) {
        const errorText = await response.text();
        console.error(`[BaseApiService] HTTP ${response.status}: ${errorText}`);
        throw new Error(`HTTP ${response.status}: ${response.statusText || '请求失败'}`);
      }

      const result: ApiResponse<T> = await response.json();

      if (result.code !== API_CONSTANTS.HTTP_STATUS.OK) {
        if (result.code === API_CONSTANTS.HTTP_STATUS.UNAUTHORIZED) {
          this.clearToken();
          if (window.location.pathname !== API_CONSTANTS.LOGIN_PATH) {
            window.location.href = API_CONSTANTS.LOGIN_PATH;
          }
        }
        throw new Error(result.msg || '请求失败');
      }

      return result;
    } catch (error: any) {
      console.error(`[BaseApiService] 请求失败 ${url}:`, error);

      if (error.name === 'TypeError' && error.message.includes('fetch')) {
        throw new Error('网络连接失败，请检查网络设置');
      }

      throw error;
    }
  }

  /**
   * GET 请求
   */
  protected async get<T>(url: string): Promise<T> {
    const response = await this.request<T>(url);
    return response.data;
  }

  /**
   * POST 请求
   */
  protected async post<T>(url: string, data: any): Promise<T> {
    const response = await this.request<T>(url, {
      method: 'POST',
      body: JSON.stringify(data),
      headers: {
        'Content-Type': 'application/json',
      },
    });
    return response.data;
  }

  /**
   * PUT 请求
   */
  protected async put<T>(url: string, data: any): Promise<T> {
    const response = await this.request<T>(url, {
      method: 'PUT',
      body: JSON.stringify(data),
      headers: {
        'Content-Type': 'application/json',
      },
    });
    return response.data;
  }

  /**
   * DELETE 请求
   */
  protected async delete<T>(url: string): Promise<T> {
    const response = await this.request<T>(url, {
      method: 'DELETE',
    });
    return response.data;
  }

  /**
   * POST 表单请求
   */
  protected async postForm<T>(url: string, data: Record<string, string>): Promise<T> {
    const formData = new URLSearchParams();
    Object.entries(data).forEach(([key, value]) => {
      formData.append(key, value);
    });

    const response = await this.request<T>(url, {
      method: 'POST',
      body: formData,
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
      },
    });
    return response.data;
  }
}
